import{_ as t,c as r,o,ag as n}from"./chunks/framework.CSeR4K32.js";const h=JSON.parse('{"title":"Preface","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/en/guide/lxd/lxd_precheck.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"OneClickVirt"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Preface"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/en/guide/lxd/lxd_precheck.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Preface"}]]},"headers":[],"relativePath":"en/guide/lxd/lxd_precheck.md","filePath":"en/guide/lxd/lxd_precheck.md","lastUpdated":1781276860000}'),a={name:"en/guide/lxd/lxd_precheck.md"};function i(s,e,c,l,d,p){return o(),r("div",null,e[0]||(e[0]=[n('<h1 id="preface" tabindex="-1">Preface <a class="header-anchor" href="#preface" aria-label="Permalink to &quot;Preface&quot;">​</a></h1><p>This page covers the standard (non-customized) workflow. Custom sections are documented separately.</p><p>If your host has no IPv6 subnet but you want to assign IPv6 addresses to containers, check the <code>Customize</code> section in the <code>LXD</code> module for <code>Attach a free IPv6 address segment to the host</code>, then attach an IPv6 subnet before installation.</p><p>Feel free to give the project a <code>Star</code> for free support!--&gt;<a href="https://github.com/oneclickvirt/lxd" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/lxd</a></p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Hardware requirements.</p><ul><li>System: Ubuntu 18+ (recommended), Debian 8+ (Incus more recommended)</li><li>Virtualization: KVM, VMWARE recommended.</li><li>Memory: At least 512MB of RAM</li><li>Hard disk: hard disk (system disk) at least 10G</li><li>Network: dedicated IPv4 address recommended; IPv6 optional; outbound Internet access required to download scripts.</li></ul><p>PS: If the hardware is very good and has a lot of resources, you can use PVE to batch open KVM virtualized VMs <a href="https://github.com/oneclickvirt/pve" target="_blank" rel="noreferrer">Jump</a></p><p>PS: If the hardware resources are even worse, virtualization is not supported, you can use the docker version, the adaption surface is wider <a href="https://github.com/oneclickvirt/docker" target="_blank" rel="noreferrer">Jump</a></p><h2 id="project-features" tabindex="-1">Project Features <a class="header-anchor" href="#project-features" aria-label="Permalink to &quot;Project Features&quot;">​</a></h2><ul><li><p>This set of script development using <strong>Ubuntu20</strong>, Ubuntu other long-term maintenance version should also be no problem, automatically switch to another storage type if btrfs not supported</p></li><li><p>Set up both TCP and UDP forwarding, in addition to SSH ports, other mapping intranet and extranet ports are the same.</p></li><li><p>Support for docker nested virtualization of open LXC containers has been set up, and the default normal version and pure probe version use the debian11 system.</p></li><li><p>lxcfs has been set to be enabled by default, so that querying resources within a container uses the configured view rather than the host&#39;s view</p></li><li><p>Includes default restrictions for abuse-prone toolchains and TCP/UDP ports (3389, 8888, 54321, 65432) to reduce scanning/bruteforce misuse risk.</p></li><li><p>Supports one-click IPv6 configuration for LXC containers when the host has a valid IPv6 subnet; subnet size is auto-detected.</p></li><li><p>Ensure that the disk you want to open is the default system disk (sda or sda1) and not the mounted disk (sdb and so on), if you are not sure, use <code>fdisk -l</code> and <code>df</code> to check.</p></li><li><p>See <a href="https://github.com/oneclickvirt/lxd/blob/main/README_other.md" target="_blank" rel="noreferrer">Other notes</a> for details on mounting other disks.</p></li><li><p>One-click scripts support custom restrictions on all content, the normal version supports multiple runs of the batch generation does not overwrite the previously generated configuration</p></li></ul><h2 id="detecting-the-environment" tabindex="-1">Detecting the environment <a class="header-anchor" href="#detecting-the-environment" aria-label="Permalink to &quot;Detecting the environment&quot;">​</a></h2><p><strong>Before running subsequent scripts, execute this check to confirm the host meets requirements.</strong></p><p>Command:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash &lt;(curl -sSLk https://raw.githubusercontent.com/oneclickvirt/lxd/main/scripts/pre_check.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',15)]))}const m=t(a,[["render",i]]);export{h as __pageData,m as default};
